const raw = $input.first().json.stdout || '';
const lines = raw.trim().split('\n').filter(l => l.trim() !== '');

// Skip header line
const dataLines = lines.slice(1);

const IGNORE = ['n8n-certbot-1'];

const containers = dataLines.map(line => {
  const parts = line.trim().split(/\s{2,}/);
  const name = parts[parts.length - 1] || 'unknown';
  const status = parts[4] || 'unknown';
  const image = parts[1] || 'unknown';
  return { name, status, image };
});

const failed = containers.filter(c =>
  !c.status.toLowerCase().startsWith('up') && !IGNORE.includes(c.name)
);
const healthy = containers.filter(c =>
  c.status.toLowerCase().startsWith('up')
);

const now = new Date().toISOString();

return [{
  json: {
    all_containers: containers,
    failed_containers: failed,
    healthy_containers: healthy,
    has_failures: failed.length > 0,
    total: containers.length,
    failed_count: failed.length,
    healthy_count: healthy.length,
    checked_at: now
  }
}];

const parseData = $('Parse Container Status').first().json;
const failed = parseData.failed_containers;
const healthy = parseData.healthy_containers;
const total = parseData.total;
const checkedAt = parseData.checked_at;

const ts = Math.floor(new Date(checkedAt).getTime() / 1000);

const failedFields = failed.map(c => ({
  name: `🔴  ${c.name}`,
  value: `**Status:** ${c.status}\n**Proposed Fix:** \`docker start ${c.name}\``,
  inline: false
}));

const healthyNames = healthy.map(c => `\`${c.name}\``).join(', ') || 'None';

return [{
  json: {
    embeds: [{
      title: '🚨  AutOps — Container Alert',
      description: `**${failed.length} of ${total} containers** are not running on \`143.198.131.159\`.\n\nReply with:\n\`!approve <name>\` — restart the container\n\`!deny <name>\` — leave it alone\n\`!logs <name>\` — view recent logs`,
      color: 15158332,
      fields: [
        ...failedFields,
        {
          name: '✅  Healthy Containers',
          value: healthyNames,
          inline: false
        },
        {
          name: '🕐  Detected At',
          value: `<t:${ts}:F>`,
          inline: false
        }
      ],
      footer: {
        text: 'AutOps Monitoring — autops.online'
      }
    }]
  }
}];

// Pure logic embedded into the AutOps Health Check workflow's Code nodes by
// patch-healthcheck.mjs. Kept here so the behaviour guarding the shared
// pending_actions table is unit-testable rather than trapped inside n8n.

const VALID_CONTAINER = /^[a-zA-Z0-9][a-zA-Z0-9_.-]{0,63}$/;

// The exact command this workflow generates. Recovery only clears rows it owns.
const automatedCommand = container => `docker start ${container}`;

const SCHEDULE_RULE = { interval: [{ field: 'minutes', minutesInterval: 5 }] };

// n8n treats `{rule:{interval:[{}]}}` as a DAILY schedule: an interval entry
// with no explicit `field` silently means "once a day".
function scheduleIntervalMinutes(rule) {
  const entry = rule?.interval?.[0];
  if (!entry || !entry.field) return 1440;
  if (entry.field === 'minutes') return entry.minutesInterval;
  if (entry.field === 'hours') return (entry.hoursInterval ?? 1) * 60;
  if (entry.field === 'days') return (entry.daysInterval ?? 1) * 1440;
  return null;
}

// Build the rows the health check may write. The data table has no NOT NULL
// support, so this is the only thing standing between a malformed container
// and an approvable row.
function buildRows(failedContainers, now = new Date().toISOString()) {
  const rows = [];
  for (const item of failedContainers) {
    const container = String(item?.name || '').trim();
    const status = String(item?.status || '').trim();
    if (!VALID_CONTAINER.test(container)) continue;
    if (!status) continue;
    rows.push({ container, command: automatedCommand(container), status, detected_at: now });
  }
  return rows;
}

// Rows to clear: the container is healthy again and the row holds this
// workflow's own automated command; or the row is malformed and unactionable.
function planRecovery(pendingRows, healthyContainers) {
  const healthy = new Set(healthyContainers.map(c => c.name));
  const resolved = [];
  for (const row of pendingRows) {
    if (!row.container || !row.command) {
      resolved.push({ id: row.id, container: row.container, command: row.command, reason: 'malformed row' });
      continue;
    }
    if (!healthy.has(row.container)) continue;
    if (row.command.trim() !== automatedCommand(row.container)) continue;
    resolved.push({ id: row.id, container: row.container, command: row.command, reason: 'container recovered' });
  }
  return resolved;
}


// The data table cannot enforce NOT NULL, so this is the enforcement point.
const failed = $input.all().map(item => item.json);
return buildRows(failed).map(json => ({ json }));

